--x1. Câți clienți sunt în baza de date?SELECT COUNT(*)FROM Sales.Customer--x2. Când a fost făcută prima comandă?SELECT MIN(OrderDate)FROM Sales.SalesOrderHeader--x3. Care este primul produs în ordine alfabetică?SELECT MIN(Name)FROM Production.Product--x4. Care este valoarea medie a unei comenzi?SELECT AVG(TotalDue)FROM Sales.SalesOrderHeader--x5. Valoarea taxelor plătite în anul 2014?SELECT SUM(TaxAmt)FROM Sales.SalesOrderHeaderWHERE YEAR(OrderDate) = 2014--x6. Care e data ultimei comenzi ?SELECT MAX(OrderDate)FROM Sales.SalesOrderHeader--x7. Angajatul cu salariul cel mai mareSELECT TOP (1) WITH TIES eph.BusinessEntityIDFROM HumanResources.EmployeePayHistory ephWHERE eph.RateChangeDate = ( SELECT MAX(eph2.RateChangeDate)							 FROM HumanResources.EmployeePayHistory AS eph2						     WHERE eph2.BusinessEntityID = eph.BusinessEntityID)ORDER BY (eph.Rate * eph.PayFrequency) DESC--x8. Câte departamente sunt în companie?SELECT COUNT(*)FROM HumanResources.Department--x9. Anul în care am încasat cei mai mulți baniSELECT YEAR(OrderDate)FROM Sales.SalesOrderHeaderGROUP BY YEAR(OrderDate)HAVING SUM(TotalDue) = (SELECT MAX(Incasari)						FROM (SELECT SUM(TotalDue) AS Incasari							  FROM Sales.SalesOrderHeader							  GROUP BY YEAR(OrderDate)) x)